// Certified value-door gate — integrated bench.
//
// This is the measurement that turns "the cost-aware gate is going to pay off"
// into a number. It pits THREE schedulers against each other on the SAME work:
//
//   * serial         — the baseline (no dispatch at all).
//   * frf_auto       — the DEFAULT path (`engine::execute` → size-gated
//                      `compute_k_eff`). It stays serial below N=16 but still
//                      OPENS THE DOOR on cheap large-N (e.g. N=4096 → k_eff=32),
//                      paying turbulent dispatch on work that never amortizes it.
//   * frf_certified  — the CERT path (`engine::execute_with_certified_cost`). The
//                      admission cert attests per-item work; the value-door
//                      crossover keeps cheap work LAMINAR (serial) at every N and
//                      opens the door only for genuinely heavy work.
//
// Two per-item costs (the cert's attested class), swept across N:
//   * CHEAP  (x + 1.0, attested ~1 ns)            — laminar; certified must stay serial.
//   * HEAVY  (~256-iter fma, attested ~300 ns)    — turbulent; certified must parallelize.
//
// The topline story: on CHEAP×large-N, frf_certified should track SERIAL while
// frf_auto pays the over-dispatch; on HEAVY, frf_certified should track frf_auto
// (both open the door). Where the certified gate keeps flow laminar is exactly
// where the win shows up. Run: `cargo bench --bench bench_certified_gate`.

use divan::black_box;
use divan::Bencher;
use gnosis_frf::engine::execute_with_certified_cost;
use gnosis_frf::slice::SliceMutProducer;

fn main() {
    divan::main();
}

const SIZES: &[usize] = &[8, 16, 64, 256, 1024, 4096, 16384];

// Per-item cost the admission cert attests (ns). Compared to the platform
// per-item dispatch cost (default 100 ns) by the value-door crossover.
const CHEAP_CERT_NS: u64 = 1;
const HEAVY_CERT_NS: u64 = 300;

#[inline]
fn heavy(seed: f64) -> f64 {
    let mut acc = seed;
    for _ in 0..256 {
        acc = acc.mul_add(1.0000001, 1.0);
    }
    acc
}

// ---- CHEAP per-item work: certified gate must keep it LAMINAR (serial) -------
#[divan::bench(args = SIZES)]
fn cheap_serial(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    });
}

#[divan::bench(args = SIZES)]
fn cheap_frf_auto(bencher: Bencher, n: usize) {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(*x + 1.0));
    });
}

#[divan::bench(args = SIZES)]
fn cheap_frf_certified(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        execute_with_certified_cost(
            SliceMutProducer { slice: &mut data },
            |iter| {
                for x in iter {
                    *x = black_box(*x + 1.0);
                }
            },
            CHEAP_CERT_NS,
        );
    });
}

// ---- HEAVY per-item work: certified gate must OPEN the door -----------------
#[divan::bench(args = SIZES)]
fn heavy_serial(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.iter_mut().for_each(|x| *x = black_box(heavy(*x)));
    });
}

#[divan::bench(args = SIZES)]
fn heavy_frf_auto(bencher: Bencher, n: usize) {
    use gnosis_frf::prelude::{IntoParallelRefMutIterator, ParallelIterator};
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        data.par_iter_mut().for_each(|x| *x = black_box(heavy(*x)));
    });
}

#[divan::bench(args = SIZES)]
fn heavy_frf_certified(bencher: Bencher, n: usize) {
    let mut data = vec![0.0f64; n];
    bencher.bench_local(|| {
        execute_with_certified_cost(
            SliceMutProducer { slice: &mut data },
            |iter| {
                for x in iter {
                    *x = black_box(heavy(*x));
                }
            },
            HEAVY_CERT_NS,
        );
    });
}
